"use client";

/**
 * FileUploader Component
 *
 * A drag & drop file upload zone for SaaS applications.
 * Optimized for Product Mode with clean, efficient file management.
 *
 * @example
 * ```tsx
 * <FileUploader
 *   accept={['image/*', '.pdf']}
 *   maxFiles={5}
 *   maxSize={10 * 1024 * 1024}
 *   onFilesAdded={(files) => handleUpload(files)}
 * />
 * ```
 */

import { forwardRef, useRef, useState, useCallback } from "react";
import {
  Upload,
  File,
  FileImage,
  FileText,
  FileVideo,
  FileAudio,
  X,
  AlertCircle,
  CheckCircle,
  Loader2,
} from "lucide-react";
import type { FileUploaderProps } from "./FileUploader.types";
import styles from "./FileUploader.module.css";

// Get icon based on file type
const getFileIcon = (type: string) => {
  if (type.startsWith("image/")) return FileImage;
  if (type.startsWith("video/")) return FileVideo;
  if (type.startsWith("audio/")) return FileAudio;
  if (type.includes("pdf") || type.includes("document")) return FileText;
  return File;
};

// Format file size
const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
};

export const FileUploader = forwardRef<HTMLDivElement, FileUploaderProps>(
  (
    {
      accept,
      maxFiles,
      maxSize,
      multiple = true,
      onFilesAdded,
      onFileRemove,
      files = [],
      disabled = false,
      dropzoneContent,
      placeholder = "Drag and drop files here, or click to browse",
      showFileList = true,
      compact = false,
      variant = "default",
      error,
      helperText,
      className,
      ...rest
    },
    ref,
  ) => {
    const inputRef = useRef<HTMLInputElement>(null);
    const [isDragging, setIsDragging] = useState(false);
    const [dragError, setDragError] = useState<string | null>(null);

    const validateFiles = useCallback(
      (fileList: FileList | File[]): { valid: File[]; errors: string[] } => {
        const valid: File[] = [];
        const errors: string[] = [];
        const filesArray = Array.from(fileList);

        // Check max files
        if (maxFiles && files.length + filesArray.length > maxFiles) {
          errors.push(`Maximum ${maxFiles} files allowed`);
          return { valid, errors };
        }

        filesArray.forEach((file) => {
          // Check file size
          if (maxSize && file.size > maxSize) {
            errors.push(
              `${file.name} exceeds maximum size of ${formatFileSize(maxSize)}`,
            );
            return;
          }

          // Check file type
          if (accept && accept.length > 0) {
            const isAccepted = accept.some((type) => {
              if (type.startsWith(".")) {
                return file.name.toLowerCase().endsWith(type.toLowerCase());
              }
              if (type.endsWith("/*")) {
                return file.type.startsWith(type.replace("/*", "/"));
              }
              return file.type === type;
            });
            if (!isAccepted) {
              errors.push(`${file.name} is not an accepted file type`);
              return;
            }
          }

          valid.push(file);
        });

        return { valid, errors };
      },
      [accept, maxFiles, maxSize, files.length],
    );

    const handleFiles = useCallback(
      (fileList: FileList | File[]) => {
        if (disabled) return;

        const { valid, errors } = validateFiles(fileList);

        if (errors.length > 0 && errors[0]) {
          setDragError(errors[0]);
          setTimeout(() => setDragError(null), 3000);
        }

        if (valid.length > 0) {
          onFilesAdded?.(valid);
        }
      },
      [disabled, validateFiles, onFilesAdded],
    );

    const handleDragOver = useCallback(
      (e: React.DragEvent) => {
        e.preventDefault();
        if (!disabled) {
          setIsDragging(true);
        }
      },
      [disabled],
    );

    const handleDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
    }, []);

    const handleDrop = useCallback(
      (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        handleFiles(e.dataTransfer.files);
      },
      [handleFiles],
    );

    const handleInputChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
          handleFiles(e.target.files);
        }
        // Reset input value to allow selecting the same file again
        e.target.value = "";
      },
      [handleFiles],
    );

    const handleClick = () => {
      if (!disabled) {
        inputRef.current?.click();
      }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
      if ((e.key === "Enter" || e.key === " ") && !disabled) {
        e.preventDefault();
        inputRef.current?.click();
      }
    };

    const acceptString = accept?.join(",");

    const classNames = [
      styles.fileUploader,
      styles[variant],
      compact && styles.compact,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    const dropzoneClasses = [
      styles.dropzone,
      isDragging && styles.dropzoneDragging,
      disabled && styles.dropzoneDisabled,
      (error || dragError) && styles.dropzoneError,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Dropzone */}
        <div
          className={dropzoneClasses}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          onClick={handleClick}
          onKeyDown={handleKeyDown}
          role="button"
          tabIndex={disabled ? -1 : 0}
          aria-disabled={disabled}
        >
          <input
            ref={inputRef}
            type="file"
            className={styles.input}
            accept={acceptString}
            multiple={multiple}
            onChange={handleInputChange}
            disabled={disabled}
            aria-hidden="true"
          />

          {dropzoneContent || (
            <div className={styles.dropzoneContent}>
              <div className={styles.dropzoneIcon}>
                <Upload size={compact ? 20 : 24} />
              </div>
              <p className={styles.dropzonePlaceholder}>{placeholder}</p>
              {!compact && (
                <div className={styles.dropzoneHints}>
                  {accept && (
                    <span className={styles.dropzoneHint}>
                      Accepted: {accept.join(", ")}
                    </span>
                  )}
                  {maxSize && (
                    <span className={styles.dropzoneHint}>
                      Max size: {formatFileSize(maxSize)}
                    </span>
                  )}
                  {maxFiles && (
                    <span className={styles.dropzoneHint}>
                      Max files: {maxFiles}
                    </span>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Helper text or error */}
        {(error || dragError || helperText) && (
          <div
            className={`${styles.helperText} ${error || dragError ? styles.helperTextError : ""}`}
          >
            {error || dragError || helperText}
          </div>
        )}

        {/* File list */}
        {showFileList && files.length > 0 && (
          <ul className={styles.fileList}>
            {files.map((file) => {
              const FileIcon = getFileIcon(file.type);
              return (
                <li key={file.id} className={styles.fileItem}>
                  <div className={styles.fileIcon}>
                    {file.preview ? (
                      <img
                        src={file.preview}
                        alt=""
                        className={styles.filePreview}
                      />
                    ) : (
                      <FileIcon size={20} />
                    )}
                  </div>
                  <div className={styles.fileInfo}>
                    <span className={styles.fileName}>{file.name}</span>
                    <span className={styles.fileSize}>
                      {formatFileSize(file.size)}
                    </span>
                  </div>
                  <div className={styles.fileStatus}>
                    {file.status === "uploading" && (
                      <>
                        <div className={styles.progressBar}>
                          <div
                            className={styles.progressFill}
                            style={{ width: `${file.progress || 0}%` }}
                          />
                        </div>
                        <Loader2 size={16} className={styles.fileStatusIcon} />
                      </>
                    )}
                    {file.status === "completed" && (
                      <CheckCircle
                        size={16}
                        className={styles.fileStatusSuccess}
                      />
                    )}
                    {file.status === "error" && (
                      <AlertCircle
                        size={16}
                        className={styles.fileStatusError}
                      />
                    )}
                  </div>
                  {onFileRemove && (
                    <button
                      type="button"
                      className={styles.fileRemove}
                      onClick={(e) => {
                        e.stopPropagation();
                        onFileRemove(file.id);
                      }}
                      aria-label={`Remove ${file.name}`}
                    >
                      <X size={16} />
                    </button>
                  )}
                </li>
              );
            })}
          </ul>
        )}
      </div>
    );
  },
);

FileUploader.displayName = "FileUploader";

/**
 * FileUploader Component Types
 *
 * Type definitions for the Orion FileUploader section component.
 * A drag & drop file upload zone for SaaS applications.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Uploaded file item
 */
export interface UploadedFile {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * File name
   */
  name: string;

  /**
   * File size in bytes
   */
  size: number;

  /**
   * MIME type
   */
  type: string;

  /**
   * Upload progress (0-100)
   */
  progress?: number;

  /**
   * Upload status
   */
  status: "pending" | "uploading" | "completed" | "error";

  /**
   * Error message if status is 'error'
   */
  error?: string;

  /**
   * Preview URL (for images)
   */
  preview?: string;

  /**
   * Original File object
   */
  file?: File;
}

/**
 * FileUploader section props
 *
 * @example
 * ```tsx
 * <FileUploader
 *   accept={['image/*', '.pdf']}
 *   maxFiles={5}
 *   maxSize={10 * 1024 * 1024}
 *   onFilesAdded={(files) => handleUpload(files)}
 * />
 * ```
 */
export interface FileUploaderProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "onChange"
> {
  /**
   * Accepted file types (MIME types or extensions)
   */
  accept?: string[];

  /**
   * Maximum number of files
   */
  maxFiles?: number;

  /**
   * Maximum file size in bytes
   */
  maxSize?: number;

  /**
   * Allow multiple files
   * @default true
   */
  multiple?: boolean;

  /**
   * Callback when files are added
   */
  onFilesAdded?: (files: File[]) => void;

  /**
   * Callback when a file is removed
   */
  onFileRemove?: (fileId: string) => void;

  /**
   * Current uploaded files (controlled)
   */
  files?: UploadedFile[];

  /**
   * Disabled state
   */
  disabled?: boolean;

  /**
   * Custom dropzone content
   */
  dropzoneContent?: ReactNode;

  /**
   * Custom placeholder text
   * @default "Drag and drop files here, or click to browse"
   */
  placeholder?: string;

  /**
   * Show file list below dropzone
   * @default true
   */
  showFileList?: boolean;

  /**
   * Compact mode
   * @default false
   */
  compact?: boolean;

  /**
   * Variant style
   * @default "default"
   */
  variant?: "default" | "minimal" | "card";

  /**
   * Error message
   */
  error?: string;

  /**
   * Helper text
   */
  helperText?: string;
}

/**
 * FileUploader Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Clean drag & drop zone with efficient file management.
 */

.fileUploader {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-3);
}

/* ============================================================================
 * DROPZONE
 * ============================================================================ */

.dropzone {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-8);
  border: 2px dashed var(--border-subtle);
  border-radius: var(--radius-control);
  background: var(--surface-subtle);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.dropzone:hover {
  border-color: var(--border-default);
  background: var(--surface-layer);
}

.dropzone:focus-visible {
  outline: 2px solid var(--interactive-primary);
  outline-offset: 2px;
}

.dropzoneDragging {
  border-color: var(--interactive-primary);
  background: var(--surface-layer);
}

.dropzoneDisabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.dropzoneDisabled:hover {
  border-color: var(--border-subtle);
  background: var(--surface-subtle);
}

.dropzoneError {
  border-color: var(--text-error);
}

.input {
  display: none;
}

.dropzoneContent {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-3);
  text-align: center;
}

.dropzoneIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  border-radius: var(--radius-full);
  background: var(--surface-base);
  color: var(--text-tertiary);
}

.dropzonePlaceholder {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  margin: 0;
}

.dropzoneHints {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--spacing-2) var(--spacing-4);
}

.dropzoneHint {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
}

/* ============================================================================
 * HELPER TEXT
 * ============================================================================ */

.helperText {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
}

.helperTextError {
  color: var(--text-error);
}

/* ============================================================================
 * FILE LIST
 * ============================================================================ */

.fileList {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
  list-style: none;
  margin: 0;
  padding: 0;
}

.fileItem {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  padding: var(--spacing-2) var(--spacing-3);
  background: var(--surface-subtle);
  border-radius: var(--radius-sm);
}

.fileIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: var(--radius-sm);
  background: var(--surface-base);
  color: var(--text-secondary);
  flex-shrink: 0;
  overflow: hidden;
}

.filePreview {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.fileInfo {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-0-5);
}

.fileName {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-primary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.fileSize {
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
}

.fileStatus {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.progressBar {
  width: 60px;
  height: 4px;
  background: var(--surface-layer);
  border-radius: var(--radius-full);
  overflow: hidden;
}

.progressFill {
  height: 100%;
  background: var(--interactive-primary);
  transition: width var(--mode-hover-duration);
}

.fileStatusIcon {
  color: var(--text-tertiary);
  animation: spin 1s linear infinite;
}

.fileStatusSuccess {
  color: var(--text-success);
}

.fileStatusError {
  color: var(--text-error);
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.fileRemove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: none;
  border: none;
  border-radius: var(--radius-sm);
  color: var(--text-tertiary);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
  flex-shrink: 0;
}

.fileRemove:hover {
  background: var(--surface-layer);
  color: var(--text-error);
}

/* ============================================================================
 * VARIANTS
 * ============================================================================ */

/* Minimal variant */
.minimal .dropzone {
  padding: var(--spacing-4);
  border-style: solid;
  border-width: 1px;
}

.minimal .dropzoneIcon {
  width: 32px;
  height: 32px;
}

/* Card variant */
.card .dropzone {
  padding: var(--spacing-6);
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  box-shadow: var(--mode-shadow-default);
}

.card .dropzone:hover {
  box-shadow: var(--mode-shadow-hover);
}

/* ============================================================================
 * COMPACT MODE
 * ============================================================================ */

.compact .dropzone {
  padding: var(--spacing-4);
}

.compact .dropzoneIcon {
  width: 32px;
  height: 32px;
}

.compact .dropzonePlaceholder {
  font-size: var(--font-size-13);
}

.compact .dropzoneHints {
  display: none;
}

.compact .fileItem {
  padding: var(--spacing-1-5) var(--spacing-2);
}

.compact .fileIcon {
  width: 28px;
  height: 28px;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 480px) {
  .dropzone {
    padding: var(--spacing-6);
  }

  .dropzoneHints {
    flex-direction: column;
    gap: var(--spacing-1);
  }

  .fileItem {
    flex-wrap: wrap;
  }

  .fileStatus {
    order: 3;
    width: 100%;
    margin-top: var(--spacing-2);
  }

  .progressBar {
    flex: 1;
  }
}
